"use client";

import styles from "./contactMe.module.css"
import SectionBox from "./sectionBox"
import { useEffect, useRef, useState } from "react";
import Matter from "matter-js";

export default function ContactMe() {
  return (
    <SectionBox>
      <PhysicsSection/>
      <div className={styles["contact-me-container"]}>Contact Me</div>
    </SectionBox>
  )
}

export function PhysicsSection() {
  const sceneRef = useRef(null);
  const [startPhysics, setStartPhysics] = useState(false);
  const [bodiesState, setBodiesState] = useState([]); // Para posiciones de palabras

  // Detectar ancho y alto del contenedor para responsive
  const [dimensions, setDimensions] = useState({ width: 0, height: 0 });
  useEffect(() => {
    const section = sceneRef.current as HTMLElement | null;
    if (!section) return;
    const updateSize = () => {
      setDimensions({
        width: section.offsetWidth,
        height: section.offsetHeight
      });
    };
    updateSize();
    window.addEventListener("resize", updateSize);
    return () => window.removeEventListener("resize", updateSize);
  }, []);

  useEffect(() => {
    if (!startPhysics) return;

    const {
      Engine,
      Render,
      Runner,
      Bodies,
      World,
      Events,
    } = Matter;

    const section = sceneRef.current as HTMLElement | null;
    if (!section) return;

    // Engine
    const engine = Engine.create();
    const world = engine.world;

    // Palabras a mostrar
    const words = ["Hola", "Next.js", "React", "Portfolio", "Contacto", "Web", "OpenAI"];
    // Distribuir palabras proporcionalmente al ancho
    const wordBodies = words.map((word, i) =>
      Bodies.rectangle(
        (dimensions.width / (words.length + 1)) * (i + 1),
        0,
        Math.max(80, dimensions.width / 5), // ancho responsive mínimo 80
        50,
        {
          restitution: 0.8,
          render: { fillStyle: "#fff0", strokeStyle: "#fff0" },
          label: word
        }
      )
    );

    // Render
    const render = Render.create({
      element: section,
      engine: engine,
      options:
       {
        width: section.clientWidth,
        height: section.clientHeight,
        wireframes: false,
        background: "transparent",
        pixelRatio: window.devicePixelRatio || 1
      }
    });

    Render.run(render);
    const runner = Runner.create();
    Runner.run(runner, engine);

    // Suelo y paredes
    const ground = Bodies.rectangle(
      section.clientWidth / 2,
      section.clientHeight - 10,
      section.clientWidth,
      20,
      {
        isStatic: true,
        render: { fillStyle: "skyblue", visible: false }
      }
    );
    const leftWall = Bodies.rectangle(0, section.clientHeight / 2, 20, section.clientHeight, {
      isStatic: true,
      render: { fillStyle: "skyblue", visible: false }
    });
    const rightWall = Bodies.rectangle(
      section.clientWidth,
      section.clientHeight / 2,
      20,
      section.clientHeight,
      {
        isStatic: true,
        render: { fillStyle: "skyblue", visible: false }
      }
    );
    World.add(world, [ground, leftWall, rightWall]);

    // Agregar palabras con delay
    wordBodies.forEach((body, i) => {
      setTimeout(() => {
        World.add(world, body);
      }, i * 400); // 400ms entre cada palabra
    });

    // Actualizar posiciones en cada frame
    const update = () => {
      setBodiesState(
        wordBodies.map((body, i) => ({
          x: body.position.x,
          y: body.position.y,
          angle: body.angle,
          word: words[i]
        }))
      );
      requestAnimationFrame(update);
    };
    update();

    // Cleanup
    return () => {
      Render.stop(render);
      Runner.stop(runner);
      World.clear(world);
      Engine.clear(engine);
      render.canvas.remove();
      render.textures = {};
    };
  }, [startPhysics, dimensions]);

  return (
    <div
      style={{
        maxWidth: "100%",
        width: "100%",
        height: dimensions.width < 600 ? "32vh" : "60vh", // más bajo en mobile
        maxHeight: "80vh",
        backgroundColor: "skyblue",
        display: "flex",
        alignItems: "center",
        justifyContent: "center",
        position: "relative"
      }}
    >
      <section
        ref={sceneRef}
        style={{
          width: "100%",
          height: "100%",
          overflow: "hidden",
        }}
      />
      {/* Overlay de palabras */}
      {bodiesState.map(({ x, y, angle, word }, i) => (
        <span
          key={i}
          style={{
            position: "absolute",
            left: x - 60, // centrar
            top: y - 25,
            width: 120,
            height: 50,
            display: "flex",
            alignItems: "center",
            justifyContent: "center",
            fontWeight: "bold",
            fontSize: 22,
            color: "#222",
            background: "rgba(255,255,255,0.7)",
            borderRadius: 12,
            transform: `rotate(${angle}rad)`,
            pointerEvents: "none",
            userSelect: "none"
          }}
        >
          {word}
        </span>
      ))}
    </div>
  );
}